const mexcTickers = $('MEXC Tickers').first().json;
const jupTokens = $input.first().json;

// Build MEXC USDT price map: symbol → price
const mexcPriceMap = {};
for (const ticker of mexcTickers) {
  if (typeof ticker.symbol === 'string' && ticker.symbol.endsWith('USDT')) {
    const base = ticker.symbol.slice(0, -4);
    mexcPriceMap[base] = parseFloat(ticker.price);
  }
}

// Map Jupiter symbol → mint (first verified match only)
const jupMintMap = {};
for (const token of jupTokens) {
  const sym = (token.symbol || '').toUpperCase();
  if (sym && mexcPriceMap[sym] !== undefined && !jupMintMap[sym]) {
    jupMintMap[sym] = token.address;
  }
}

// Build common tokens list
const commonTokens = [];
for (const [sym, mint] of Object.entries(jupMintMap)) {
  commonTokens.push({ symbol: sym, mint, mexcPrice: mexcPriceMap[sym] });
}

// Jupiter API limit: 100 ids per request
const batch = commonTokens.slice(0, 100);
const mintIds = batch.map(t => t.mint).join(',');

return [{ json: { commonTokens: batch, mintIds, totalCommon: commonTokens.length } }];

const { commonTokens } = $('Find Common Tokens').first().json;
const jupResponse = $input.first().json;
const priceData = jupResponse.data || {};
const spreads = [];

for (const token of commonTokens) {
  const jupData = priceData[token.mint];
  if (!jupData || !jupData.price) continue;

  const mexcPrice = token.mexcPrice;
  const jupPrice = parseFloat(jupData.price);

  if (jupPrice === 0 || isNaN(jupPrice) || isNaN(mexcPrice)) continue;

  const spreadPct = ((mexcPrice - jupPrice) / jupPrice) * 100;
  const absSpread = Math.abs(spreadPct);

  if (absSpread >= 5) {
    spreads.push({
      symbol: token.symbol,
      mexcPrice: mexcPrice.toFixed(8),
      jupPrice: jupPrice.toFixed(8),
      spreadPct: spreadPct.toFixed(2),
      absSpread: absSpread.toFixed(2),
      direction: spreadPct > 0 ? 'Buy JUP → Sell MEXC' : 'Buy MEXC → Sell JUP'
    });
  }
}

spreads.sort((a, b) => parseFloat(b.absSpread) - parseFloat(a.absSpread));

return [{ json: {
  spreads,
  hasAlerts: spreads.length > 0,
  count: spreads.length,
  timestamp: new Date().toISOString()
} }];

